        term: entry.term,
        normalized_term: entry.normalizedTerm,
        source_lang: entry.sourceLang,
        target_lang: entry.targetLang,
        entry_data: entry,
        created_at: new Date().toISOString()
      }, { onConflict: 'normalized_term, source_lang, target_lang' });
  } catch {}
}

