export async function upsertProfile(profile: UserProfile) {
  if (!profile.telegramId) return;
  try {
    // 1. Sync identity (Mirror)
    // We run this as a separate, non-blocking call. If it fails (e.g., 404), it doesn't stop the app sync.
    supabase
